30	async function edgeIssueCsrfToken(secret: string, now: number): Promise<string> {
31	  const nonceBytes = new Uint8Array(18);
32	  crypto.getRandomValues(nonceBytes);
33	  const nonce = b64url(nonceBytes);
34	  const exp = now + 12 * 60 * 60 * 1000;
35	  const payload = `${nonce}.${exp}`;
36	  const key = await crypto.subtle.importKey(
37	    "raw",
38	    new TextEncoder().encode(secret),
39	    { name: "HMAC", hash: "SHA-256" },
40	    false,
41	    ["sign"],
42	  );
43	  const sig = new Uint8Array(
44	    await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(payload)),
45	  );
46	  return `${payload}.${b64url(sig)}`;
47	}
