49	function b64url(bytes: Uint8Array): string {
50	  let s = "";
51	  for (const b of bytes) s += String.fromCharCode(b);
52	  return btoa(s).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
53	}
