72	 * the CSRF cookie is purely a defence-in-depth nonce.
73	 */
74	export async function middleware(request: NextRequest) {
75	  const { pathname } = request.nextUrl;
76	  const needsAuth = PROTECTED_PREFIXES.some((p) => pathname.startsWith(p));
77	  if (!needsAuth) {
